class SideNavbarControls{constructor(){document.getElementById("side-navigation-close-button").onclick=()=>{this.closeNav()},document.getElementById("side-navigation-open-button").onclick=()=>{this.openNav()}}openNav(){document.getElementById("side-navigation").style.width="16em"}closeNav(){document.getElementById("side-navigation").style.width="0"}}export{SideNavbarControls};